import{_ as a,o as i,c as e,a2 as o}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Installation","description":"DinOdds Plugin Installation","frontmatter":{"title":"Installation","description":"DinOdds Plugin Installation","weight":20,"extra":{"order":20},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/installation"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/installation"}],["meta",{"property":"og:title","content":"Installation"}],["meta",{"property":"og:description","content":"DinOdds Plugin Installation"}],["meta",{"name":"twitter:title","content":"Installation"}],["meta",{"name":"twitter:description","content":"DinOdds Plugin Installation"}]]},"headers":[],"relativePath":"docs/dinodds/installation.md","filePath":"docs/dinodds/installation.md"}'),n={name:"docs/dinodds/installation.md"};function l(d,t,s,r,c,h){return i(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="plugin-installation" tabindex="-1">Plugin Installation <a class="header-anchor" href="#plugin-installation" aria-label="Permalink to &quot;Plugin Installation&quot;">​</a></h1><p>You can install the plugin either through WordPress dashboard (recommended) or via FTP.</p><hr><h2 id="before-installation" tabindex="-1">Before Installation <a class="header-anchor" href="#before-installation" aria-label="Permalink to &quot;Before Installation&quot;">​</a></h2><p>Please make sure your server meets the minimum <a href="/docs/dinodds/">system requirements</a> and download the plugin file from your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a>.</p><h3 id="install-through-wordpress-dashboard" tabindex="-1">Install through WordPress Dashboard <a class="header-anchor" href="#install-through-wordpress-dashboard" aria-label="Permalink to &quot;Install through WordPress Dashboard&quot;">​</a></h3><ol><li>Visit WordPress dashboard → Plugins and click <code>Add New</code> and <code>Upload Plugin</code> after that</li><li>Click <code>Choose File</code>, select the plugin file <code>dinodds.zip</code> and click <code>Install Now</code></li><li>Activate the plugin</li></ol><h3 id="install-via-ftp" tabindex="-1">Install via FTP <a class="header-anchor" href="#install-via-ftp" aria-label="Permalink to &quot;Install via FTP&quot;">​</a></h3><ol><li>Log in to your server with your FTP credentials, using an FTP client, cPanel or similar</li><li>Navigate to <code>plugins</code> directory from your WordPress website root</li><li>Upload the plugin file <code>dinodds.zip</code> to <code>plugins</code> directory</li><li>Unzip the archive, you&#39;ll have a directory <code>dinodds</code> in plugins</li><li>Remove the <code>dinodds.zip</code> file</li><li>Visit WordPress dashboard → Plugins and activate the plugin</li></ol>',9)])])}const m=a(n,[["render",l]]);export{p as __pageData,m as default};
